import {
  ContextMenu,
  ContextMenuTrigger,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuLabel,
  ContextMenuSeparator,
} from '@shery-ui/components';

export default function ContextMenuDemo() {
  return (
    <ContextMenu>
      <ContextMenuTrigger className='p-10 items-center justify-center rounded-lg border border-dashed text-sm text-muted-foreground'>
        Right click here
      </ContextMenuTrigger>

      <ContextMenuContent>
        <ContextMenuLabel>Actions</ContextMenuLabel>

        <ContextMenuSeparator />

        <ContextMenuItem>New File</ContextMenuItem>
        <ContextMenuItem>Duplicate</ContextMenuItem>
        <ContextMenuItem variant='destructive'>
          Delete
        </ContextMenuItem>
      </ContextMenuContent>
    </ContextMenu>
  );
}

import {
  ContextMenu,
  ContextMenuTrigger,
  ContextMenuContent,
  ContextMenuCheckboxItem,
  ContextMenuLabel,
  ContextMenuSeparator,
} from '@shery-ui/components';
import { useState } from 'react';

export default function ContextMenuCheckboxDemo() {
  const [bookmarks, setBookmarks] = useState(true);
  const [urls, setUrls] = useState(false);

  return (
    <ContextMenu>
      <ContextMenuTrigger className='p-10 items-center justify-center rounded-lg border border-dashed text-sm text-muted-foreground'>
        Right click here
      </ContextMenuTrigger>

      <ContextMenuContent>
        <ContextMenuLabel>Preferences</ContextMenuLabel>

        <ContextMenuSeparator />

        <ContextMenuCheckboxItem
          checked={bookmarks}
          onCheckedChange={setBookmarks}
        >
          Show Bookmarks Bar
        </ContextMenuCheckboxItem>

        <ContextMenuCheckboxItem
          checked={urls}
          onCheckedChange={setUrls}
        >
          Show Full URLs
        </ContextMenuCheckboxItem>
      </ContextMenuContent>
    </ContextMenu>
  );
}

import {
  ContextMenu,
  ContextMenuTrigger,
  ContextMenuContent,
  ContextMenuRadioGroup,
  ContextMenuRadioItem,
  ContextMenuLabel,
  ContextMenuSeparator,
} from '@shery-ui/components';
import { useState } from 'react';

export default function ContextMenuRadioDemo() {
  const [position, setPosition] = useState('right');

  return (
    <ContextMenu>
      <ContextMenuTrigger className='p-10 items-center justify-center rounded-lg border border-dashed text-sm text-muted-foreground'>
        Right click here
      </ContextMenuTrigger>

      <ContextMenuContent>
        <ContextMenuLabel>Panel Position</ContextMenuLabel>

        <ContextMenuSeparator />

        <ContextMenuRadioGroup
          value={position}
          onValueChange={setPosition}
        >
          <ContextMenuRadioItem value='left'>
            Left
          </ContextMenuRadioItem>

          <ContextMenuRadioItem value='right'>
            Right
          </ContextMenuRadioItem>

          <ContextMenuRadioItem value='bottom'>
            Bottom
          </ContextMenuRadioItem>
        </ContextMenuRadioGroup>
      </ContextMenuContent>
    </ContextMenu>
  );
}
